// Helper: calcDualShadePrice(widthMm, heightMm, pricePerSqm)
function calcDualShadePrice(widthMm, heightMm, pricePerSqm) {
  const sqm = Math.max((widthMm / 1000) * (heightMm / 1000), 1.5);
  return Math.round(sqm * pricePerSqm * 100) / 100;
}

